esqlQuery.esql:
// Alert on high/disaster severity problems unacknowledged for 30+ minutes.
// Uses event.ingested as the time field to see recently collected docs,
// then filters on @timestamp (problem creation) being older than 30 minutes.
FROM logs-zabbix.problem-*
| WHERE zabbix.problem.severity IN ("high", "disaster")
  AND zabbix.problem.acknowledged == false
  AND zabbix.problem.suppressed == false
  AND `@timestamp` < NOW() - 30 minutes
| STATS problem_count = COUNT(*) BY zabbix.problem.name, zabbix.problem.severity
| WHERE problem_count >= 1
